def validate_plan(plan: dict, available_tool_names: set) -> list[str]:
    """
    Returns a list of validation errors. Empty list = plan is valid.
    """
    errors = []
    steps = plan.get("steps", [])
    step_ids = {s["step_id"] for s in steps}

    for step in steps:
        # Unknown tool
        if step["tool"] not in available_tool_names:
            errors.append(f"{step['step_id']}: unknown tool '{step['tool']}'")

        # Unsatisfiable dependency
        for dep in step.get("depends_on", []):
            if dep not in step_ids:
                errors.append(f"{step['step_id']}: depends on unknown step '{dep}'")

    # Cycle detection using DFS
    adj = {s["step_id"]: s.get("depends_on", []) for s in steps}
    visited, in_stack = set(), set()

    def has_cycle(node: str) -> bool:
        visited.add(node)
        in_stack.add(node)
        for neighbor in adj.get(node, []):
            if neighbor not in visited:
                if has_cycle(neighbor):
                    return True
            elif neighbor in in_stack:
                return True
        in_stack.discard(node)
        return False

    for step_id in step_ids:
        if step_id not in visited:
            if has_cycle(step_id):
                errors.append(f"Dependency cycle detected involving step '{step_id}'")
                break

    return errors

available = {t["name"] for t in AVAILABLE_TOOLS}
errors = validate_plan(plan, available)
if errors:
    print("Plan invalid:", errors)
else:
    print("Plan is valid. Ready to execute.")

import anthropic
import json

client = anthropic.Anthropic()

INCREMENTAL_PLANNER_SYSTEM = """
You are an incremental planning agent.
You receive: a goal, completed steps so far, and their results.
Produce the NEXT 1-3 steps needed to progress toward the goal.

If the goal is achieved by the completed steps, return:
{{"done": true, "summary": "..."}}

Otherwise return:
{{"done": false, "next_steps": [... 1-3 step objects ...]}}

Step format: {{"step_id": "sN", "tool": "...", "args": {{...}}, "depends_on": [], "description": "..."}}
"""

def plan_next_steps(goal: str, completed: list[dict], tool_list: str) -> dict:
    context = f"Goal: {goal}\n\n"
    if completed:
        context += "Completed steps and results:\n"
        for step in completed:
            context += f"- {step['step_id']} ({step['tool']}): {step.get('result', 'no result')}\n"
    else:
        context += "No steps completed yet.\n"

    system = INCREMENTAL_PLANNER_SYSTEM + f"\nAvailable tools:\n{tool_list}"
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        system=system,
        messages=[{"role": "user", "content": context}],
    )
    try:
        return json.loads(resp.content[0].text)
    except json.JSONDecodeError:
        return {"done": False, "next_steps": []}

def run_incremental_planner_executor(goal: str, available_tools: list, dispatch: dict) -> dict:
    tool_list = format_tool_list(available_tools)
    completed = []
    step_counter = 1

    for _ in range(10):  # max planning rounds
        plan_result = plan_next_steps(goal, completed, tool_list)

        if plan_result.get("done"):
            return {"status": "complete", "summary": plan_result.get("summary", "")}

        next_steps = plan_result.get("next_steps", [])
        if not next_steps:
            return {"status": "stuck", "reason": "Planner returned no next steps"}

        # Execute each step
        for step in next_steps:
            tool_name = step["tool"]
            args = step["args"]
            fn = dispatch.get(tool_name)
            result = fn(**args) if fn else json.dumps({"error": f"Unknown: {tool_name}"})
            completed.append({**step, "result": result})
            step_counter += 1

    return {"status": "max_planning_rounds", "completed": len(completed)}
